import numpy as np


class Graph:
    """A minimal undirected, unweighted graph on nodes 0..n-1."""

    def __init__(self, n_nodes):
        self.n = n_nodes
        self.adj = {i: set() for i in range(n_nodes)}

    def add_edge(self, u, v):
        """Add one undirected edge between u and v."""
        self.adj[u].add(v)
        self.adj[v].add(u)

    def adjacency_matrix(self):
        """Return the n x n adjacency matrix A as a numpy array."""
        A = np.zeros((self.n, self.n))
        for u in range(self.n):
            for v in self.adj[u]:
                A[u][v] = 1.0
        return A

    def degree_matrix(self):
        """Return the n x n diagonal degree matrix D as a numpy array."""
        D = np.zeros((self.n, self.n))
        for i in range(self.n):
            D[i][i] = len(self.adj[i])
        return D

    def laplacian(self):
        """Return the graph Laplacian L = D - A."""
        return self.degree_matrix() - self.adjacency_matrix()


def message_passing(graph, features, weight):
    """One round of GNN message passing."""
    features = np.asarray(features, dtype=float)
    weight = np.asarray(weight, dtype=float)
    A = graph.adjacency_matrix()
    row_sums = A.sum(axis=1, keepdims=True)
    row_sums[row_sums == 0] = 1.0
    A_norm = A / row_sums
    aggregated = A_norm @ features
    return aggregated @ weight
